/* PasstheEPPP — Question Bank Batch 8
   Enhanced rationale format — all questions explain why wrong answers are wrong
   ~80 new questions across all 8 domains */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch8 = [
        // ===== Domain 1: Biological Bases (10) =====
        {domainId:1, q:"Parkinson's disease is primarily associated with degeneration of dopaminergic neurons in the:", options:["Hippocampal area","Substantia nigra","Cerebellar paths","Amygdala complex"], answer:1, difficulty:"easy", rationale:"Correct: (B) Parkinson's disease results from loss of dopamine-producing neurons in the substantia nigra pars compacta, leading to motor symptoms: resting tremor, rigidity, bradykinesia, and postural instability.\n\nWhy others are wrong:\n(A) Hippocampus degeneration → Alzheimer's disease and memory impairment\n(C) Cerebellar degeneration → ataxia and coordination problems, not Parkinson's motor symptoms\n(D) Amygdala dysfunction → emotional processing problems, not the motor symptoms of Parkinson's"},
        {domainId:1, q:"The corpus callosum connects:", options:["The specific frontal and parietal lobes","The left and right cerebral hemispheres","The cerebrum and the entire cerebellum","The thalamus and the core hypothalamus"], answer:1, difficulty:"easy", rationale:"Correct: (B) The corpus callosum is the largest white matter tract, containing ~200 million axons connecting homologous areas of the two hemispheres. Severing it (split-brain surgery) prevents interhemispheric communication.\n\nWhy others are wrong:\n(A) Frontal-parietal connections are within-hemisphere association tracts (e.g., superior longitudinal fasciculus)\n(C) Cerebrum-cerebellum connection = cerebellar peduncles, not the corpus callosum\n(D) Thalamus-hypothalamus connections are subcortical fiber tracts, not the corpus callosum"},
        {domainId:1, q:"Long-term potentiation (LTP) is considered the neural basis of:", options:["Affective emotional regulation","Learning and memory formation","Visual and sensory perception","Complex somatic motor control"], answer:1, difficulty:"medium", rationale:"Correct: (B) LTP is a persistent strengthening of synaptic connections following high-frequency stimulation. It's the leading cellular model of how memories are encoded, primarily studied in the hippocampus.\n\nWhy others are wrong:\n(A) Emotional regulation involves the prefrontal cortex-amygdala circuit, not specifically LTP\n(C) Sensory perception involves sensory cortex processing, not synaptic potentiation\n(D) Motor coordination is primarily cerebellar function, not hippocampal LTP"},
        {domainId:1, q:"Phenylketonuria (PKU) is an example of:", options:["A distinct chromosomal gene abnormality","An autosomal recessive genetic disorder","A sex-linked inherited genetic disorder","A complex systemic autoimmune condition"], answer:1, difficulty:"medium", rationale:"Correct: (B) PKU is an autosomal recessive disorder caused by a mutation on chromosome 12 affecting the enzyme phenylalanine hydroxylase. Without dietary intervention, phenylalanine accumulates and causes intellectual disability.\n\nWhy others are wrong:\n(A) Chromosomal abnormalities involve extra/missing chromosomes (e.g., Down syndrome = trisomy 21) — PKU is a single-gene mutation\n(C) Sex-linked disorders are on the X chromosome (e.g., color blindness, hemophilia) — PKU is on chromosome 12 (autosomal)\n(D) Autoimmune diseases involve the immune system attacking self-tissue (e.g., MS, lupus) — PKU is genetic/metabolic"},
        {domainId:1, q:"The reticular activating system (RAS) is primarily responsible for:", options:["Complex visual processing","Arousal and consciousness","Basic language processing","Core memory consolidation"], answer:1, difficulty:"medium", rationale:"Correct: (B) The RAS is a network in the brainstem that filters incoming stimuli and regulates wakefulness, arousal, and the sleep-wake cycle. Damage to the RAS can result in coma.\n\nWhy others are wrong:\n(A) Visual processing occurs in the occipital lobe (primary visual cortex)\n(C) Language comprehension → Wernicke's area in the left temporal lobe\n(D) Memory consolidation → hippocampus and related medial temporal structures"},
        {domainId:1, q:"Neuroplasticity refers to:", options:["The brain's complete structural inability to change after reaching late childhood","The brain's ability to reorganize and form new neural connections throughout life","The progressive structural hardening of complex neural tissue occurring with age","The naturally fixed and comprehensively rigid nature of mature brain architecture"], answer:1, difficulty:"easy", rationale:"Correct: (B) Neuroplasticity = the brain's capacity to reorganize structurally and functionally in response to experience, learning, or injury. It occurs across the lifespan, though it's greatest in early development.\n\nWhy others are wrong:\n(A) The brain CAN change after childhood — neuroplasticity continues throughout life, just at reduced rates\n(C) 'Hardening' is not a real neurological concept — the brain maintains plasticity\n(D) Brain structure is NOT fixed — it changes with experience, learning, and injury recovery"},
        {domainId:1, q:"The pituitary gland is often called the 'master gland' because it:", options:["Is objectively the single largest specialized endocrine gland","Controls the release of hormones from other endocrine glands","Produces strictly only one primary designated target hormone","Is structurally located entirely within the core frontal lobe"], answer:1, difficulty:"easy", rationale:"Correct: (B) The pituitary releases trophic hormones (TSH, ACTH, FSH, LH, GH, prolactin) that regulate other endocrine glands (thyroid, adrenals, gonads), though it is itself regulated by the hypothalamus.\n\nWhy others are wrong:\n(A) The thyroid is larger; the pituitary is pea-sized — size isn't why it's the 'master gland'\n(C) The pituitary produces MANY hormones (anterior and posterior lobes each produce multiple)\n(D) It's located at the base of the brain, attached to the hypothalamus via the infundibulum, not in the frontal lobe"},
        {domainId:1, q:"Huntington's disease is caused by:", options:["A specific recessive gene on chromosome 12","An autosomal dominant gene on chromosome 4","An explicit massive deletion on chromosome X","Chronic severe environmental toxic exposure"], answer:1, difficulty:"hard", rationale:"Correct: (B) Huntington's is caused by an autosomal dominant mutation (CAG trinucleotide repeat expansion) on chromosome 4. Each child of an affected parent has a 50% chance of inheriting it. Symptoms typically appear ages 30-50.\n\nWhy others are wrong:\n(A) Chromosome 12 recessive = PKU; Huntington's is chromosome 4 dominant\n(C) X-chromosome deletions cause sex-linked disorders; Huntington's is autosomal (chromosome 4)\n(D) Huntington's is purely genetic — environmental factors don't cause it (though they may influence symptom onset)"},
        {domainId:1, q:"The occipital lobe is primarily responsible for:", options:["Auditory encoding","Motor programming","Visual processing","Tactile sensation"], answer:2, difficulty:"easy", rationale:"Correct: (C) The occipital lobe contains the primary visual cortex (V1) and visual association areas. Damage causes cortical blindness, visual agnosia, or visual field deficits depending on the specific area affected.\n\nWhy others are wrong:\n(A) Auditory processing = temporal lobe (primary auditory cortex in Heschl's gyrus)\n(B) Motor planning = frontal lobe (premotor cortex and supplementary motor area)\n(D) Somatosensory processing = parietal lobe (postcentral gyrus)"},
        {domainId:1, q:"Tardive dyskinesia is a side effect most associated with:", options:["Selective serotonin reuptake inhibitors","Standard short-acting benzodiazepine drugs","First-generation (typical) antipsychotics","Lithium carbonate mood stabilizing agents"], answer:2, difficulty:"medium", rationale:"Correct: (C) Tardive dyskinesia (involuntary movements, especially of the face and tongue) results from chronic dopamine D2 receptor blockade by typical antipsychotics (haloperidol, chlorpromazine). It can be irreversible.\n\nWhy others are wrong:\n(A) SSRIs may cause serotonin syndrome or sexual side effects, not TD\n(B) Benzodiazepines cause sedation, dependence, and paradoxical disinhibition — not TD\n(D) Lithium side effects include tremor, thyroid/kidney issues, and toxicity — not TD"},

        // ===== Domain 2: Cognitive-Affective (10) =====
        {domainId:2, q:"The availability heuristic leads people to:", options:["Consistently seek exhaustive additional formal information before deciding","Judge the likelihood of events based on how easily examples come to mind","Systematically seek exhaustive additional formal data prior to deciding","Strictly ignore explicit emotional context information in rapid decisions"], answer:1, difficulty:"easy", rationale:"Correct: (B) The availability heuristic (Tversky & Kahneman): events that are easily recalled (vivid, recent, emotionally charged) are judged as more probable. E.g., overestimating plane crash risk after seeing news coverage.\n\nWhy others are wrong:\n(A) Using statistical probabilities = normative/rational decision-making, the opposite of heuristic shortcuts\n(C) Seeking additional info = systematic processing, not a heuristic shortcut\n(D) Emotional information actually INCREASES availability, making it more influential, not less"},
        {domainId:2, q:"According to the dual-process theory, System 1 thinking is:", options:["Slow, deliberate, and logical","Fast, automatic, and intuitive","Reserved solely for math tasks","Strictly superior to System 2"], answer:1, difficulty:"medium", rationale:"Correct: (B) System 1 (Kahneman): fast, automatic, effortless, intuitive processing based on heuristics and associations. Operates continuously and handles most daily decisions.\n\nWhy others are wrong:\n(A) Slow, deliberate, analytical = System 2 thinking (the complementary system)\n(C) System 1 is used for ALL domains — pattern recognition, social judgments, language comprehension — not just math\n(D) System 1 is often LESS accurate — it produces systematic biases and errors that System 2 can sometimes correct"},
        {domainId:2, q:"Elaborative rehearsal differs from maintenance rehearsal in that it:", options:["Simply repeats targeted information to passively hold it in short-term memory","Creates meaningful connections between new information and existing knowledge","Is fundamentally significantly less effective for durable long-term retention","Exclusively functions and works properly strictly for pure visual information"], answer:1, difficulty:"easy", rationale:"Correct: (B) Elaborative rehearsal creates deep, meaningful associations (linking to existing knowledge, creating imagery, generating examples), producing superior long-term retention through deeper encoding.\n\nWhy others are wrong:\n(A) Simple repetition = maintenance rehearsal (rote repetition to keep info in STM)\n(C) Elaborative rehearsal is MORE effective for long-term retention — that's its primary advantage\n(D) It works for all types of information — verbal, visual, conceptual, procedural"},
        {domainId:2, q:"The 'cocktail party effect' demonstrates:", options:["That typical human adults cannot continuously process two conversations simultaneously","Selective attention — the ability to focus on one conversation while filtering others","That explicit short-term active memory is robustly enhanced in busy social settings","That fundamental sensory hearing dramatically and completely degrades in noisy contexts"], answer:1, difficulty:"easy", rationale:"Correct: (B) The cocktail party effect (Cherry, 1953): you can focus on one voice among many, yet still detect personally relevant information (like your name) from unattended channels, demonstrating selective attention.\n\nWhy others are wrong:\n(A) People CAN detect salient information from unattended conversations, showing some parallel processing\n(C) Memory enhancement in social settings is a social facilitation effect, not the cocktail party effect\n(D) The phenomenon is specifically about attention allocation, not hearing degradation"},
        {domainId:2, q:"Functional fixedness is a cognitive bias that:", options:["Reliably and uniquely enhances fluid active specific problem solving","Prevents seeing objects as having uses beyond their typical function","Explicitly and reliably improves semantic memory for functional items","Directly helps in grouping basic specified routine objects effectively"], answer:1, difficulty:"medium", rationale:"Correct: (B) Functional fixedness = inability to see novel uses for objects because of fixation on their conventional function. E.g., not thinking to use a coin as a screwdriver. It's a barrier to creative problem solving.\n\nWhy others are wrong:\n(A) It IMPAIRS creative problem solving — it's a cognitive limitation, not an enhancement\n(C) Functional fixedness is about problem solving, not memory improvement\n(D) While categorization uses typical functions, functional fixedness specifically refers to being STUCK on those categories during problem solving"},
        {domainId:2, q:"The levels-of-processing framework (Craik & Lockhart) predicts that:", options:["All basic cognitive encoding strategies produce exactly comparable memory","Deeper semantic processing produces better memory than shallow processing","Extended active rehearsal duration is essentially the single memory factor","Visual cognitive processing is always robustly deeper than verbal processing"], answer:1, difficulty:"medium", rationale:"Correct: (B) Craik & Lockhart (1972): deeper processing (semantic meaning, self-referencing) produces stronger, more durable memories than shallow processing (physical features like font or sound).\n\nWhy others are wrong:\n(A) Encoding strategies are NOT equal — depth of processing directly affects retention quality\n(C) Time spent is less important than DEPTH — shallow rehearsal for a long time is less effective than brief deep processing\n(D) Depth is not modality-dependent — verbal semantic processing can be deeper than visual surface processing"},
        {domainId:2, q:"Prospective memory refers to:", options:["Accurately recalling remote discrete personal experiences","Remembering to perform intended actions in the future","Semantic mechanisms explicitly storing objective facts","Episodic pathways capturing explicit subjective events"], answer:1, difficulty:"medium", rationale:"Correct: (B) Prospective memory = remembering to do something in the future (take medication, attend a meeting). It involves both time-based (at 3pm) and event-based (when I see John) cues.\n\nWhy others are wrong:\n(A) Remembering past events = retrospective memory (the traditional study of memory)\n(C) Memory for facts = semantic memory (a type of declarative/explicit memory)\n(D) Memory for personal experiences = episodic memory (another type of declarative memory)"},
        {domainId:2, q:"The misinformation effect (Loftus) occurs when:", options:["People systematically properly reconstruct core details of an old event","Post-event information alters a person's memory of the original event","People naturally entirely forget precise central elements via passed time","People incorrectly absolutely substitute explicit dreams with pure reality"], answer:1, difficulty:"medium", rationale:"Correct: (B) Loftus's research shows that misleading post-event information (leading questions, false details) can alter or create false memories. E.g., 'How fast were the cars going when they SMASHED?' vs 'contacted.'\n\nWhy others are wrong:\n(A) Accurate recall is the opposite of the misinformation effect\n(C) Forgetting due to time = decay theory, not the misinformation effect (which involves active distortion)\n(D) Dream-reality confusion = source monitoring error, a different memory phenomenon"},
        {domainId:2, q:"Maslow's hierarchy of needs places which need at the TOP?", options:["Safety protection","Interpersonal love","Self-actualization","Esteem achievement"], answer:2, difficulty:"easy", rationale:"Correct: (C) Self-actualization = realizing one's full potential, creativity, and personal growth. It sits atop the hierarchy: physiological → safety → belonging → esteem → self-actualization.\n\nWhy others are wrong:\n(A) Safety needs = second level (security, stability, health)\n(B) Belongingness = third level (friendship, intimacy, connection)\n(D) Esteem = fourth level (confidence, achievement, respect) — one level below self-actualization"},
        {domainId:2, q:"The representativeness heuristic leads people to:", options:["Formulate basic rational judgments directly based on actual sample size","Judge probability based on how much something resembles a typical case","Actively search out deeply comprehensive general population base rates","Intentionally successfully avoid relying on core stereotypical metrics"], answer:1, difficulty:"medium", rationale:"Correct: (B) Representativeness heuristic: judging probability by similarity to a prototype. E.g., assuming a quiet, organized person is a librarian rather than a salesperson, even when salespeople vastly outnumber librarians.\n\nWhy others are wrong:\n(A) The representativeness heuristic causes people to IGNORE sample size (the law of small numbers fallacy)\n(C) People NEGLECT base rates when using this heuristic — that's a key error it produces\n(D) It actually PROMOTES stereotypical judgments by relying on prototypical features"},

        // ===== Domain 3: Social & Cultural (10) =====
        {domainId:3, q:"The contact hypothesis (Allport) proposes that prejudice can be reduced when:", options:["Diverse groups are physically completely separated across all major community environments","Groups interact under conditions of equal status, common goals, and institutional support","One specific distinct majority group entirely and formally dominates other minority groups","Intergroup contact remains heavily brief and fundamentally superficial across all domains"], answer:1, difficulty:"medium", rationale:"Correct: (B) Allport's (1954) conditions for effective intergroup contact: equal status, common goals, intergroup cooperation, and institutional/authority support. Without these conditions, contact can actually increase prejudice.\n\nWhy others are wrong:\n(A) Separation typically maintains or increases prejudice through lack of exposure\n(C) Unequal status contact reinforces existing prejudice and stereotypes\n(D) Brief, superficial contact is insufficient — meaningful, sustained interaction under proper conditions is needed"},
        {domainId:3, q:"Sternberg's triangular theory of love includes which three components?", options:["Trust, respect, and communication","Intimacy, passion, and commitment","Attraction, stability, connection","Romance, friendship, and loyalty"], answer:1, difficulty:"easy", rationale:"Correct: (B) Sternberg's three components: Intimacy (emotional closeness), Passion (physical attraction and arousal), Commitment (decision to maintain the relationship). Different combinations produce different love types (e.g., consummate love = all three).\n\nWhy others are wrong:\n(A) Trust/respect/communication are relationship factors but not Sternberg's specific components\n(C) Attraction/compatibility/stability are not the theoretical components Sternberg identified\n(D) Romance/friendship/loyalty overlap with Sternberg's concepts but aren't his exact terminology"},
        {domainId:3, q:"The just-world hypothesis (Lerner) leads people to:", options:["Actively support any victims of severe injustice","Believe that people deserve what happens to them","Consistently challenge broad systemic inequality","Recognize the explicit role of luck in outcomes"], answer:1, difficulty:"medium", rationale:"Correct: (B) The just-world hypothesis: people need to believe the world is fair and orderly. This leads to blaming victims ('they must have done something to deserve it') to maintain belief in a just world.\n\nWhy others are wrong:\n(A) The just-world belief often REDUCES helping by rationalizing victims' suffering as deserved\n(C) Belief in a just world can actually JUSTIFY systemic inequality ('the system rewards merit')\n(D) The just-world hypothesis specifically DENIES the role of luck — outcomes are seen as deserved"},
        {domainId:3, q:"In-group bias refers to:", options:["Explicit baseline preference for targeted individuals outside one's group","The tendency to favor members of one's own group over out-group members","Systematically objective and strictly equal treatment of distinct groups","Pervasive baseline bias directed specifically against one's group members"], answer:1, difficulty:"easy", rationale:"Correct: (B) In-group bias (in-group favoritism): preferential treatment, more positive evaluations, and greater resource allocation to members of one's own groups. It occurs even in minimal group paradigms (Tajfel).\n\nWhy others are wrong:\n(A) Preferring out-group members = out-group favoritism, which is rare and usually occurs in marginalized groups\n(C) Equal treatment of all groups = absence of bias, the opposite\n(D) Bias against one's own group = in-group derogation, which can occur in stigmatized groups but is not 'in-group bias'"},
        {domainId:3, q:"According to the social comparison theory (Festinger), people compare themselves to others primarily to:", options:["Routinely feel superior to specific others","Evaluate their own abilities and opinions","Conform precisely to standard group norms","Reduce any internal cognitive dissonance"], answer:1, difficulty:"medium", rationale:"Correct: (B) Festinger (1954): people have a fundamental drive to evaluate their abilities and opinions. When objective standards are unavailable, they compare with similar others (lateral comparison).\n\nWhy others are wrong:\n(A) Feeling superior = downward social comparison (comparing with worse-off others), only one type of comparison\n(C) Conformity is a separate process — comparison is about self-evaluation, not necessarily adjusting to norms\n(D) Reducing dissonance is Festinger's OTHER major theory, separate from social comparison theory"},
        {domainId:3, q:"Stereotype threat (Steele & Aronson) refers to:", options:["Explicit conscious hostile prejudice uniquely directed toward a specific targeted group","The risk of confirming a negative stereotype about one's group, which impairs performance","The systematic explicit use of generalized stereotypes to safely predict active behavior","Broad explicit structural discrimination occurring specifically within corporate hiring"], answer:1, difficulty:"medium", rationale:"Correct: (B) Stereotype threat: awareness of a negative stereotype about one's group creates anxiety and cognitive load that impairs performance on the stereotyped dimension. E.g., women performing worse on math tests when gender is made salient.\n\nWhy others are wrong:\n(A) Conscious prejudice = explicit bias; stereotype threat is about the TARGET experiencing the threat, not the prejudiced person\n(C) Using stereotypes to predict behavior = profiling or statistical discrimination, not stereotype threat\n(D) Hiring discrimination = institutional racism/sexism, a different phenomenon from the performance-impairing effects of stereotype threat"},
        {domainId:3, q:"Acculturative stress is MOST likely when an individual adopts which acculturation strategy?", options:["Integration approach","Assimilation concept","Marginalization path","Separation framework"], answer:2, difficulty:"hard", rationale:"Correct: (C) Marginalization (rejecting both original culture AND host culture) produces the highest acculturative stress and poorest psychological outcomes. The individual lacks cultural support from both communities.\n\nWhy others are wrong:\n(A) Integration (maintaining original culture while adopting host culture) is associated with the BEST outcomes and lowest stress\n(B) Assimilation (adopting host culture, abandoning original) produces moderate stress but maintains host culture support\n(D) Separation (maintaining original culture, rejecting host) provides cultural support from the heritage community, producing less stress than marginalization"},
        {domainId:3, q:"The actor-observer bias describes:", options:["People attributing their OWN behavior to situations but OTHERS' behavior to dispositions","People universally attributing absolutely everyone's typical behavior to dispositions","People comprehensively avoiding making any active explicit interpersonal attributions","People systematically and flawlessly making perfectly objective rational attributions"], answer:0, difficulty:"medium", rationale:"Correct: (A) Actor-observer asymmetry: as actors, we attribute our behavior to situational factors ('I was late because of traffic'). As observers, we attribute others' behavior to dispositions ('She was late because she's irresponsible').\n\nWhy others are wrong:\n(B) If everyone's behavior was attributed to dispositions, there would be no actor-observer DIFFERENCE\n(C) People constantly make attributions — it's a fundamental social-cognitive process\n(D) Attributions are often systematically biased, not accurate — that's the whole point of attribution research"},
        {domainId:3, q:"Microsaggressions are:", options:["Extremely overt and systematically structured physical acts of systemic discrimination","Brief, commonplace exchanges that communicate derogatory messages to marginalized groups","Explicitly intentional and formally verifiable severe hate crimes conveying prejudice","Explicitly constructed continuous explicit verbal insults routinely given beyond context"], answer:1, difficulty:"easy", rationale:"Correct: (B) Microaggressions (Sue, 2007) are subtle, often unintentional slights — verbal, behavioral, or environmental — that communicate hostile or derogatory messages to members of marginalized groups.\n\nWhy others are wrong:\n(A) Overt discrimination = macro-level or explicit; microaggressions are subtle and often unconscious\n(C) Hate crimes are criminal acts; microaggressions are everyday interactions, usually not criminal\n(D) Microaggressions can be behavioral (clutching a purse), environmental (only White faces in marketing), or verbal — not just verbal insults"},
        {domainId:3, q:"Deindividuation occurs when:", options:["Members genuinely retain distinct personal identifiability across specific groups","Anonymity and group immersion reduce self-awareness and personal responsibility","People simply increase specific behavioral self-monitoring directly inside groups","Valid assigned groups casually become actively integrated and broadly productive"], answer:1, difficulty:"medium", rationale:"Correct: (B) Deindividuation: anonymity (costumes, darkness, online handles) and immersion in groups reduce self-awareness, weaken internal standards, and increase susceptibility to group norms — often leading to disinhibited behavior.\n\nWhy others are wrong:\n(A) Feeling identifiable PREVENTS deindividuation — accountability maintains self-regulation\n(C) Increased self-monitoring would counteract deindividuation, not cause it\n(D) Cohesion and productivity describe functional group dynamics, not the loss of individuality"},,

        // ===== Domain 4: Growth & Lifespan (10) =====
        {domainId:4, q:"Harlow's research with rhesus monkeys demonstrated that:", options:["Attachment originates entirely through basic consistent feeding","Contact comfort is more important than feeding for attachment","Monkeys consistently cannot form genuine deep early attachments","Attachment is entirely determined largely by inherited genetics"], answer:1, difficulty:"easy", rationale:"Correct: (B) Harlow's monkeys preferred the soft cloth 'mother' over the wire 'mother' with food, demonstrating that contact comfort (tactile warmth) — not feeding — is the primary basis for attachment.\n\nWhy others are wrong:\n(A) The 'cupboard theory' (attachment = feeding) is exactly what Harlow DISPROVED\n(C) Monkeys clearly DO form attachments — they clung to the cloth mother and used it as a secure base\n(D) While biology matters, the study showed that EXPERIENCE (contact comfort) is crucial, not just genetics"},
        {domainId:4, q:"The concept of 'goodness of fit' (Thomas & Chess) refers to:", options:["The match between a child's temperament and environmental demands/expectations","How particularly well a developing child naturally fits in academically overall","The objective degree that a child's physical development matches standard norms","The established continuous subjective parental satisfaction regarding their child"], answer:0, difficulty:"medium", rationale:"Correct: (A) Goodness of fit = the degree to which the child's temperament matches the demands and expectations of the environment (especially caregiver expectations). Good fit promotes positive development; poor fit increases risk.\n\nWhy others are wrong:\n(B) Academic fit is an educational concept, not Thomas & Chess's temperament theory\n(C) Physical development norms relate to growth charts and pediatric milestones, not temperament-environment match\n(D) Parental satisfaction may correlate with goodness of fit but doesn't define the concept"},
        {domainId:4, q:"Marcia's identity status of 'moratorium' is characterized by:", options:["Total lack of broad exploration and completely firm commitments","Active exploration while currently lacking definitive commitment","Consistent firm commitment exclusively without broad exploration","Broad continuous active exploration resolving in firm commitment"], answer:1, difficulty:"medium", rationale:"Correct: (B) Moratorium = actively exploring options (careers, beliefs, relationships) but hasn't yet committed. This is considered the healthiest status for adolescents — they're doing the 'identity work.'\n\nWhy others are wrong:\n(A) No exploration, no commitment = identity diffusion (most concerning status)\n(C) Commitment without exploration = foreclosure (adopted others' values without question)\n(D) Both exploration and commitment = identity achievement (the goal — they've explored and committed)"},
        {domainId:4, q:"The zone of proximal development (ZPD) represents:", options:["What a specific developing child can perfectly achieve completely independent of help","The gap between what a child can do alone and what they can do with targeted guidance","What a standard developing individual child will categorically never effectively master","The specific designated growing child's formally evaluated empirical school grade level"], answer:1, difficulty:"easy", rationale:"Correct: (B) Vygotsky's ZPD = the distance between independent problem-solving and potential with guidance from a more knowledgeable other. Instruction should target the ZPD for optimal learning.\n\nWhy others are wrong:\n(A) Independent performance = the child's actual developmental level, the LOWER boundary of the ZPD\n(C) The ZPD is specifically about what CAN be learned with help — it's about potential, not limitation\n(D) Grade level is an educational metric unrelated to Vygotsky's ZPD concept"},
        {domainId:4, q:"According to Kübler-Ross, the stages of grief include:", options:["Overt immediate shock, gradual sustained recovery, complete active lifelong acceptance","Denial, explosive overt anger, prolonged bargaining, profound depression, and acceptance","Persistent overt avoidance, active intense confrontation, comprehensive trauma integration","Comprehensive general numbness, intensive emotional yearning, total systemic reorganization"], answer:1, difficulty:"easy", rationale:"Correct: (B) Kübler-Ross's (1969) five stages: Denial, Anger, Bargaining, Depression, Acceptance (DABDA). Note: these stages are not linear or universal — people may skip stages or cycle through them.\n\nWhy others are wrong:\n(A) Shock/recovery/acceptance is an oversimplified model not attributed to Kübler-Ross\n(C) Avoidance/confrontation/integration = Worden's or another grief model, not Kübler-Ross\n(D) Numbness/yearning/disorganization/reorganization = Bowlby's phases of grief, a different model"},
        {domainId:4, q:"Selective optimization with compensation (SOC) is a theory of:", options:["Core cognitive development patterns occurring throughout early human childhood phases","Successful aging balancing specific losses alongside corresponding strategic practical gains","Adolescent identity formation focusing heavily upon complex subjective social assimilation","Prenatal physical development capturing basic internal systematic morphological expansions"], answer:1, difficulty:"medium", rationale:"Correct: (B) Baltes & Baltes (1990): older adults maintain functioning by Selecting fewer goals, Optimizing remaining abilities through practice, and Compensating for losses with new strategies or aids.\n\nWhy others are wrong:\n(A) Child cognitive development is addressed by Piaget, Vygotsky, and information processing theories\n(C) Adolescent identity = Erikson's identity vs. role confusion and Marcia's identity statuses\n(D) Prenatal development is described by embryology, not SOC"},
        {domainId:4, q:"Theory of mind typically develops around age:", options:["Typically 1 full chronologic year","Typically 2 to 3 chronologic years","Typically 4 to 5 chronologic years","Typically 8 to 10 chronologic years"], answer:2, difficulty:"medium", rationale:"Correct: (C) Theory of mind (understanding that others have beliefs, desires, and knowledge different from one's own) typically develops around age 4-5, as demonstrated by false-belief tasks (Sally-Anne test).\n\nWhy others are wrong:\n(A) At 1 year, infants have joint attention but not yet theory of mind\n(B) At 2-3, children show some precursors (pretend play, desire understanding) but fail false-belief tasks\n(D) By 8-10, theory of mind is well established — it develops much earlier"},
        {domainId:4, q:"Ainsworth's 'disorganized/disoriented' attachment (Type D) is characterized by:", options:["Consistent explicit predictable active psychological avoidance of the specified primary caregiver","Highly inconsistent, actively contradictory behaviors displaying simultaneous distress and confusion","Secure uninhibited continuous exploration effectively utilizing the caregiver as a reliable safe base","Excessive intense emotional clinging behaviors combined alongside profound resistance to true exploration"], answer:1, difficulty:"hard", rationale:"Correct: (B) Type D (Main & Hesse): contradictory behaviors reflecting an irresolvable paradox — the caregiver is both the source of comfort and the source of fear. Associated with abuse, neglect, or caregiver unresolved trauma.\n\nWhy others are wrong:\n(A) Consistent avoidance = avoidant attachment (Type A)\n(C) Secure exploration = secure attachment (Type B)\n(D) Excessive clinging with resistance = anxious-ambivalent/resistant attachment (Type C)"},
        {domainId:4, q:"'Crystallized intelligence' (Cattell) refers to:", options:["The biologically intrinsic foundational ability to effectively accurately solve strictly novel problems","The specific accumulated factual knowledge, structural vocabulary, and practical skills from experience","Standard intellectual abilities actively deteriorating completely alongside typical early adult lifespan","The overarching implicit cognitive abilities supporting heavily complex spatial and non-verbal reasoning"], answer:1, difficulty:"easy", rationale:"Correct: (B) Crystallized intelligence (Gc) = accumulated knowledge, vocabulary, and learned skills. It tends to increase or remain stable throughout adulthood because it's based on experience.\n\nWhy others are wrong:\n(A) Solving novel problems = fluid intelligence (Gf), which relies on reasoning with unfamiliar material\n(C) Crystallized intelligence typically INCREASES with age; it's FLUID intelligence that shows earlier decline\n(D) Non-verbal reasoning is more associated with fluid intelligence, not crystallized"},
        {domainId:4, q:"The 'strange situation' identified which four attachment types?", options:["Happy, directly deeply sad, sharply explicitly angry, totally overwhelmingly fearful","Securely structured, heavily avoidant, explicitly anxious-ambivalent, seriously disorganized","Independent, completely comprehensively dependent, purely codependent, thoroughly detached","Deeply formally preoccupied, actively sharply dismissing, purely fearful, solidly explicitly secure"], answer:1, difficulty:"easy", rationale:"Correct: (B) Ainsworth (original 3) + Main & Hesse (4th): Secure (B), Avoidant (A), Anxious-ambivalent/Resistant (C), and Disorganized/Disoriented (D). Based on infant reunion behavior.\n\nWhy others are wrong:\n(A) Happy/sad/angry/fearful are basic emotions (Ekman), not attachment types\n(C) Independent/dependent/codependent/detached are colloquial relationship terms, not Ainsworth's classifications\n(D) Preoccupied/dismissing/fearful/secure are Bartholomew & Horowitz's ADULT attachment styles, adapted from but not identical to the Strange Situation infant types"},

        // ===== Domain 5: Assessment (10) =====
        {domainId:5, q:"Content validity is best established through:", options:["Correlating test scores directly with a reliable distinct criterion","Expert judgment that test items adequately sample the content domain","Utilizing comprehensive exploratory and confirmatory factor analysis","Calculating extensive empirical test-retest reliability correlation"], answer:1, difficulty:"medium", rationale:"Correct: (B) Content validity = whether test items adequately represent the full content domain. Established through expert review, analysis of curriculum standards, and systematic item sampling — not statistical procedures.\n\nWhy others are wrong:\n(A) Correlating with a criterion = criterion validity (predictive or concurrent)\n(C) Factor analysis examines internal structure, related to construct validity\n(D) Test-retest correlation measures reliability (temporal stability), not validity"},
        {domainId:5, q:"IQ scores have a mean of 100 and a standard deviation of:", options:["Exactly 10","Exactly 15","Exactly 20","Exactly 25"], answer:1, difficulty:"easy", rationale:"Correct: (B) Standard IQ scores (deviation IQ): mean = 100, SD = 15. This means ~68% of scores fall between 85-115, and ~95% between 70-130. Used by WAIS, WISC, and most modern intelligence tests.\n\nWhy others are wrong:\n(A) SD of 10 = T-scores (which have mean = 50, SD = 10)\n(C) SD of 20 would spread scores too widely — 84th percentile would be IQ 120 and 98th would be 140\n(D) SD of 25 is not used in any standard IQ scoring system"},
        {domainId:5, q:"The Rorschach Inkblot Test is classified as a:", options:["Highly structured standardized personality measure","Performance-based (projective) personality measure","Standardized objective neuropsychological measure","Comprehensive valid cognitive intelligence measure"], answer:1, difficulty:"easy", rationale:"Correct: (B) The Rorschach is a performance-based (projective) test where examinees describe what they see in ambiguous inkblots. Scored using the Exner Comprehensive System or R-PAS, which provide empirical scoring.\n\nWhy others are wrong:\n(A) Structured inventories (MMPI, PAI) use standardized questions — the Rorschach uses ambiguous stimuli\n(C) Neuropsychological tests (Halstead-Reitan, WCST) assess brain-behavior relationships, not personality\n(D) Intelligence tests (WAIS, WISC) measure cognitive abilities — the Rorschach assesses personality and thought processes"},
        {domainId:5, q:"Concurrent validity is demonstrated when:", options:["Test scores reliably accurately predict distinct future outcomes","Test scores correlate with a criterion measured at the same time","The specific test superficially appears to measure what it claims","All specific formal test items are completely internally consistent"], answer:1, difficulty:"medium", rationale:"Correct: (B) Concurrent validity: the test correlates with a criterion measured at approximately the SAME TIME. E.g., a new depression scale correlating with the BDI-II administered simultaneously.\n\nWhy others are wrong:\n(A) Predicting future outcomes = predictive validity (criterion validity with a time lag)\n(C) Appearing to measure what it claims = face validity (not a true form of validity)\n(D) Internal consistency = reliability (Cronbach's alpha, split-half), not validity"},
        {domainId:5, q:"The Beck Depression Inventory (BDI-II) is:", options:["A clinician-administered diagnostic interview","A self-report measure of depression severity","A projective unstructured personality measure","A standardized measure of general intelligence"], answer:1, difficulty:"easy", rationale:"Correct: (B) The BDI-II is a 21-item self-report questionnaire measuring depression severity on a 0-63 scale. It assesses cognitive, affective, and somatic symptoms of depression.\n\nWhy others are wrong:\n(A) Clinician-administered depression interviews include the HDRS (Hamilton) and SCID\n(C) Projective tests use ambiguous stimuli (Rorschach, TAT) — the BDI has structured self-report items\n(D) The BDI measures mood/depression, not cognitive abilities like the WAIS or WISC"},
        {domainId:5, q:"Incremental validity refers to:", options:["The formal established explicit reliability of a test continuously tracking an administration","How much a test adds to prediction beyond what is already available from other sources","The distinct formal numeric established cutoff objective test passing score strictly necessary","How fundamentally basic verified testing parameters securely objectively jump reflecting age"], answer:1, difficulty:"hard", rationale:"Correct: (B) Incremental validity = the degree to which a new test improves prediction BEYOND existing measures. For a test to be clinically useful, it should add information not already available from simpler or cheaper methods.\n\nWhy others are wrong:\n(A) Validity across administrations relates to consistency/reliability and generalizability\n(C) Minimum passing score = a cut score, not a validity concept\n(D) Score increases over time could reflect practice effects or development, not incremental validity"},
        {domainId:5, q:"An intelligence test with a reliability of .95 means that:", options:["The test is statistically explicitly effectively perfectly fully valid explicitly 95% of the time directly","95% of the score variance is due to true score variance","The structured evaluated test absolutely incorrectly completely falsely fails independently 5% of the time","95% of studied diverse individuals will continuously correctly specifically score the same on strict retest"], answer:1, difficulty:"medium", rationale:"Correct: (B) Reliability = proportion of observed score variance attributable to true score variance. A reliability of .95 means 95% of score differences reflect actual ability differences, with only 5% due to measurement error.\n\nWhy others are wrong:\n(A) Reliability ≠ validity — a test can be highly reliable but not valid (consistently measuring the wrong thing)\n(C) 'Failing 5%' confuses reliability with test failure rates — the 5% is error variance, not failure\n(D) Individual retest scores will vary due to the 5% error; reliability is about the overall proportion of variance, not individual constancy"},
        {domainId:5, q:"The PAI (Personality Assessment Inventory) differs from the MMPI-2 in that it:", options:["Critically has absolutely zero embedded distinct reliability checking formalized internal validity scales","Uses a 4-point Likert scale rather than True/False","Is specifically systematically constructed completely formally purely as an implicit projective measure","Cannot adequately structurally effectively ever successfully clearly detect sophisticated malingering tests"], answer:1, difficulty:"hard", rationale:"Correct: (B) The PAI (Morey, 1991) uses a 4-point scale (False, Slightly True, Mainly True, Very True), allowing more nuanced responding than the MMPI-2's True/False format.\n\nWhy others are wrong:\n(A) The PAI HAS validity scales (Inconsistency, Infrequency, Negative Impression, Positive Impression)\n(C) The PAI is a self-report inventory, not a projective measure\n(D) The PAI CAN detect malingering through its Negative Impression Management (NIM) and Malingering Index scales"},
        {domainId:5, q:"Standard error of measurement (SEM) indicates:", options:["The strictly formal continuous calculated average baseline test score output parameter limits","The precision of individual test scores","The thoroughly tested structural valid clinical effectiveness confirming exactly all distinct validity components","The specifically explicitly assigned absolute strict psychometric distinct numeric internal item target difficulty"], answer:1, difficulty:"medium", rationale:"Correct: (B) SEM estimates the amount of error in an individual's observed score. It creates a confidence interval: observed score ± 1 SEM = 68% confidence, ± 2 SEM = 95% confidence.\n\nWhy others are wrong:\n(A) The average score is the mean, not SEM\n(C) SEM relates to RELIABILITY (measurement precision), not validity\n(D) Item difficulty is expressed as p-values (proportion answering correctly), not SEM"},
        {domainId:5, q:"A T-score of 70 on the MMPI-2 clinical scales is considered:", options:["Objectively formally placed perfectly securely tightly uniformly fully and safely within normal limits","Clinically significant/elevated","Categorically statistically securely completely comprehensively firmly thoroughly reliably exactly below typical averages","Objectively flawlessly statically smoothly completely distinctly perfectly rigorously cleanly universally average expectations"], answer:1, difficulty:"medium", rationale:"Correct: (B) On the MMPI-2, T-scores ≥ 65 are considered clinically significant, and T ≥ 70 is clearly elevated. Since T-scores have mean = 50 and SD = 10, a T of 70 is 2 SDs above the mean.\n\nWhy others are wrong:\n(A) Normal limits on MMPI-2 clinical scales are generally T < 65\n(C) T = 70 is ABOVE average (2 SDs above the mean), not below\n(D) Average would be T = 50 (the mean for T-scores)"},

        // ===== Domain 6: Treatment (10) =====
        {domainId:6, q:"Behavioral activation for depression is based on the principle that:", options:["Actively changing specific thoughts rapidly changes behavior","Increasing engagement in rewarding activities improves mood","Deep insight into unconscious conflicts resolves depression","Targeted clinical medication is necessary for full recovery"], answer:1, difficulty:"medium", rationale:"Correct: (B) Behavioral activation (Jacobson, Martell) targets the withdrawal-avoidance cycle of depression. By scheduling activities that provide mastery and pleasure, the reinforcement contingencies shift, improving mood.\n\nWhy others are wrong:\n(A) Changing thoughts first = cognitive therapy approach; behavioral activation focuses on BEHAVIOR as the entry point\n(C) Insight into unconscious conflicts = psychodynamic approach to depression\n(D) Medication addresses biological factors; behavioral activation is a standalone evidence-based psychotherapy"},
        {domainId:6, q:"Solution-focused brief therapy (SFBT) emphasizes:", options:["Analyzing deep fundamental root causes of problems","Building solutions rather than analyzing problems","Prolonged intensive deep psychodynamic exploration","Structured progressive systematic desensitization"], answer:1, difficulty:"easy", rationale:"Correct: (B) SFBT (de Shazer, Berg) focuses on what's already working and builds on strengths/exceptions. Key techniques: miracle question, scaling questions, exception-finding, and compliments.\n\nWhy others are wrong:\n(A) SFBT explicitly avoids extensive problem analysis — it's future-and-solution focused\n(C) Long-term exploration = psychodynamic therapy; SFBT is typically 3-8 sessions\n(D) Systematic desensitization = behavioral treatment for anxiety, not a solution-focused technique"},
        {domainId:6, q:"Transference in psychodynamic therapy refers to:", options:["The trained therapist's own explicit emotional reactions toward the client","The client projecting feelings from past relationships onto the therapist","Literally transferring formal clinical care from one therapist to another","Actively formally teaching the designated client effective new coping skills"], answer:1, difficulty:"easy", rationale:"Correct: (B) Transference = the client unconsciously redirects feelings, attitudes, and expectations from significant past relationships (especially parents) onto the therapist. It's a central therapeutic tool in psychodynamic work.\n\nWhy others are wrong:\n(A) Therapist's emotional reactions = countertransference (the complementary concept)\n(C) Changing therapists is a clinical logistics issue, not the psychodynamic concept of transference\n(D) Teaching skills = psychoeducation or cognitive-behavioral approach, not transference"},
        {domainId:6, q:"Eye Movement Desensitization and Reprocessing (EMDR) was originally developed for:", options:["Obsessive-compulsive disorder","Post-traumatic stress disorder","Generalized anxiety disorders","Treatment-resistant depression"], answer:1, difficulty:"easy", rationale:"Correct: (B) EMDR (Shapiro, 1987) was developed for PTSD. It uses bilateral stimulation (eye movements, tapping) during trauma memory processing to reduce distress and negative cognitions associated with traumatic memories.\n\nWhy others are wrong:\n(A) OCD first-line = ERP (exposure and response prevention) and SSRIs\n(C) GAD first-line = CBT, relaxation training, SSRIs\n(D) Depression first-line = CBT, behavioral activation, IPT, or antidepressants"},
        {domainId:6, q:"Token economies are an application of:", options:["Classical conditioning","Operant conditioning","Humanistic psychology","Psychodynamic theory"], answer:1, difficulty:"easy", rationale:"Correct: (B) Token economies use operant conditioning principles — tokens (secondary reinforcers) are earned for desired behaviors and exchanged for backup reinforcers (privileges, items). Used in psychiatric units, classrooms, and residential programs.\n\nWhy others are wrong:\n(A) Classical conditioning involves stimulus-stimulus associations, not token reinforcement for behavior\n(C) Humanistic psychology emphasizes self-actualization and unconditional positive regard, not behavioral reinforcement\n(D) Psychodynamic theory focuses on unconscious processes and insight, not behavioral contingency management"},
        {domainId:6, q:"The stages of change (Transtheoretical Model) include:", options:["Formal initial assessment, active treatment, complete termination","Precontemplation, contemplation, preparation, action, maintenance","Initial denial, direct anger, bargaining, depression, acceptance","Basic trust, autonomy, initiative, complex industry, and identity"], answer:1, difficulty:"easy", rationale:"Correct: (B) Prochaska & DiClemente's TTM stages: Precontemplation (not considering change), Contemplation (ambivalent), Preparation (planning), Action (implementing change), Maintenance (sustaining change). Some add Relapse and Termination.\n\nWhy others are wrong:\n(A) Assessment/treatment/termination are phases of clinical work, not the TTM\n(C) These are Kübler-Ross's stages of grief, not stages of behavior change\n(D) These are Erikson's psychosocial stages (first five), not the TTM"},
        {domainId:6, q:"Structural family therapy (Minuchin) focuses on:", options:["Deeply individual intrapsychic emotional personal conflicts","Family organizational patterns, boundaries, and hierarchies","The complex multigenerational transmission of severe anxiety","Employing highly strategic explicit paradoxical interventions"], answer:1, difficulty:"medium", rationale:"Correct: (B) Minuchin's structural approach examines and restructures family organization: boundaries (rigid, diffuse, clear), subsystems (parental, sibling), hierarchies, and coalitions. Uses techniques like enactment, joining, and boundary making.\n\nWhy others are wrong:\n(A) Individual intrapsychic focus = psychodynamic/psychoanalytic therapy, not family systems\n(C) Multigenerational anxiety transmission = Bowen's family systems theory (differentiation of self, triangulation)\n(D) Paradoxical interventions = strategic family therapy (Haley, Madanes), not structural"},
        {domainId:6, q:"Clozapine is unique among antipsychotics because it:", options:["Has virtually zero documented adverse side effects","Is effective for treatment-resistant schizophrenia","Exclusively formally treats only positive symptoms","Is entirely the first antipsychotic ever developed"], answer:1, difficulty:"medium", rationale:"Correct: (B) Clozapine is the gold-standard for treatment-resistant schizophrenia (patients failing 2+ other antipsychotics). Despite its efficacy, it requires regular blood monitoring due to the risk of agranulocytosis.\n\nWhy others are wrong:\n(A) Clozapine has significant side effects: agranulocytosis (potentially fatal), weight gain, metabolic syndrome, sedation\n(C) Clozapine is actually better than other antipsychotics at treating BOTH positive and negative symptoms\n(D) Chlorpromazine (Thorazine) was the first antipsychotic (1952); clozapine came later (1970s, reintroduced 1990)"},
        {domainId:6, q:"In group therapy, 'universality' (Yalom) refers to:", options:["The primary therapist treating all assigned members exactly the same","Members discovering that others share similar problems and feelings","Always formally employing purely identical treatment upon all members","A distinct structural technique regularly utilized in all modalities"], answer:1, difficulty:"easy", rationale:"Correct: (B) Universality is one of Yalom's 11 therapeutic factors: the realization that 'I'm not alone' — others have similar struggles, fears, and experiences. This reduces isolation and shame.\n\nWhy others are wrong:\n(A) Treating members identically ignores individual differences and therapeutic needs\n(C) Same treatment for all = manualized group protocol, not the therapeutic factor of universality\n(D) Universality is a curative factor specific to group therapy, not a technique used across all modalities"},
        {domainId:6, q:"Aversion therapy pairs an undesirable behavior with:", options:["A positive reinforcer","An aversive stimulus","A clear token reward","Active social praise"], answer:1, difficulty:"easy", rationale:"Correct: (B) Aversion therapy uses classical conditioning to pair an unwanted behavior (e.g., alcohol consumption) with an aversive stimulus (e.g., nausea-inducing drug like disulfiram, or electric shock), creating a conditioned aversion.\n\nWhy others are wrong:\n(A) Positive reinforcers would INCREASE the unwanted behavior, not decrease it\n(C) Token rewards = positive reinforcement in a token economy, the opposite approach\n(D) Social praise would reinforce, not discourage, the behavior"}
    ];

    batch8.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch8.length} additional questions (batch 8 — enhanced rationales).`);
})();
